package hw02.view;

import java.awt.BorderLayout;
import java.awt.Graphics;

import javax.swing.JFrame;
import javax.swing.JPanel;
import javax.swing.border.EmptyBorder;
import javax.swing.JTextField;
import javax.swing.JButton;
import java.awt.event.ActionListener;
import java.awt.event.ActionEvent;

/**
 * @author rlmse
 * A GUI representing a view displaying the model of moving balls
 */
public class ViewGUI extends JFrame {

	/**
	 * Auto-generated ID
	 */
	private static final long serialVersionUID = -38501937628770671L;

	/**
	 * The pane containing all the content of the GUI
	 */
	private JPanel contentPane;

	/**
	 * The GUI's north panel, which contains elements for controlling which balls the model
	 * generates
	 */
	private final JPanel controlPanel = new JPanel();

	/**
	 * A text field to input which type of ball is generated of the model
	 */
	private final JTextField ballTextField = new JTextField();

	/**
	 * A button which triggers the process to make the ball specified in the text field
	 */
	private final JButton makeBallButton = new JButton("Make ball");

	/**
	 * A button which clears all the balls generated by the model from the view
	 */
	private final JButton clearButton = new JButton("Clear all");

	/**
	 * The center panel of the GUI, contains the balls generated by the model
	 */
	private final JPanel ballWorld = new JPanel() {
		/**
		 * Auto-generated ID
		 */
		private static final long serialVersionUID = -3824415969248765824L;

		@Override
		public void paintComponent(Graphics g) {
			super.paintComponent(g);
			ViewGUI.this.view2ModelAdpt.paintBalls(g);
		}
	};

	/**
	 * An adapter which allows the view to communicate to the model
	 */
	private final IView2ModelAdapter view2ModelAdpt;

	/**
	 * Create the frame.
	 * @param view2ModelAdpt - the adapter allowing the view to communicate to the model
	 */
	public ViewGUI(IView2ModelAdapter view2ModelAdpt) {
		this.view2ModelAdpt = view2ModelAdpt;
		ballTextField.setToolTipText("Input class name of ball to be generated");
		ballTextField.setColumns(10);
		initGUI();
	}

	/**
	 * Contains the initialization processes for the ViewGUI
	 */
	private void initGUI() {
		setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
		setBounds(100, 100, 450, 300);
		contentPane = new JPanel();
		contentPane.setBorder(new EmptyBorder(5, 5, 5, 5));
		contentPane.setLayout(new BorderLayout(0, 0));
		setContentPane(contentPane);
		controlPanel.setToolTipText("Panel to control the balls which appear in the GUI");

		contentPane.add(controlPanel, BorderLayout.NORTH);

		controlPanel.add(ballTextField);
		makeBallButton.addActionListener(new ActionListener() {
			public void actionPerformed(ActionEvent e) {
				ViewGUI.this.view2ModelAdpt.makeBall(ViewGUI.this.ballTextField.getText());
			}
		});
		makeBallButton.setToolTipText("Make the ball of the type in the text field");

		controlPanel.add(makeBallButton);
		clearButton.addActionListener(new ActionListener() {
			public void actionPerformed(ActionEvent e) {
				ViewGUI.this.view2ModelAdpt.clearBalls();
			}
		});
		clearButton.setToolTipText("Clear all the balls from the GUI");

		controlPanel.add(clearButton);
		ballWorld.setToolTipText("Panel in which the balls appear and move around");

		contentPane.add(ballWorld, BorderLayout.CENTER);
	}

	/**
	 * Makes the GUI visible
	 */
	public void start() {
		setVisible(true);
	}

	/**
	 * @return - The panel containing the balls. Makes it easier for the View2ModelAdapter to pass
	 * information about the dimensions of the panel along to the model
	 */
	public JPanel getBallWorld() {
		return this.ballWorld;
	}

	/**
	 * Updates the GUI to reflect changes from the model
	 */
	public void update() {
		this.ballWorld.repaint();
	}

}
